208	// ===================== 规则引擎 =====================
209	
210	function evalCondition(customer, cond) {
211	  const val = customer[cond.field];
212	  if (val === undefined) return false;
213	
214	  switch (cond.op) {
215	    case 'eq': return val === cond.value;
216	    case 'neq': return val !== cond.value;
217	    case 'gt': return val > cond.value;
218	    case 'gte': return val >= cond.value;
219	    case 'lt': return val < cond.value;
220	    case 'lte': return val <= cond.value;
221	    case 'in': return Array.isArray(cond.value) && cond.value.includes(val);
222	    case 'contains': return typeof val === 'string' && val.toLowerCase().includes(String(cond.value).toLowerCase());
223	    default: return false;
224	  }
225	}
226	
227	function matchRule(customer, rule) {
228	  if (rule.all) return rule.all.every(c => evalCondition(customer, c));
229	  if (rule.any) return rule.any.some(c => evalCondition(customer, c));
230	  return false;
231	}
