250	// ===================== 评分引擎 =====================
251	
252	const TIER_BASE = { p0: 100, p1: 70, p2: 45, p3: 20, p4: 0 };
253	
254	function scoreCustomer(customer, scoring, rules) {
255	  const w = scoring.weights;
256	  let score = TIER_BASE[customer.tier] || 0;
257	
258	  // 时效惩罚：每多1天扣分
259	  score -= (customer.daysAgo || 0) * w.daysAgo_penalty.value;
260	
261	  // 客户最近回复加分
262	  if (customer.lastCustomerMsgDays !== undefined && customer.lastCustomerMsgDays <= 1) {
263	    score += w.lastCustomerMsg_bonus.value;
264	  }
265	
266	  // 核心市场加分
267	  if (rules.core_markets.includes(customer.country)) {
268	    score += w.core_market_bonus.value;
269	  }
270	
271	  // 下单信号加分
272	  if (customer.hasOrderSignal) {
273	    score += w.order_signal_bonus.value;
274	  }
275	
276	  // PI+地址加分
277	  if (customer.hasPI && customer.hasAddress) {
278	    score += w.pi_address_bonus.value;
279	  }
280	
281	  // 高互动加分
282	  if (customer.realMsgs >= 30) {
283	    score += w.high_engagement_bonus.value;
284	  }
285	
286	  // 客户消息占比高加分
287	  if (customer.cRatio >= 40) {
288	    score += w.customer_reply_bonus.value;
289	  }
290	
291	  // 沉默惩罚
292	  const silence = rules.silence_warnings[customer.tier];
293	  if (silence && customer.lastCustomerMsgDays >= silence.danger) {
294	    score -= w.silence_penalty.value;
295	  }
296	
297	  return { ...customer, score };
298	}
