321	// ===================== 沉默风险检测 =====================
322	
323	function checkSilence(customer, rules) {
324	  const silence = rules.silence_warnings[customer.tier];
325	  if (!silence) return 'normal';
326	  const d = customer.lastCustomerMsgDays;
327	  if (d === undefined || d >= 900) return 'normal'; // 未知/元数据默认值，不报警
328	  if (d >= silence.danger) return 'danger';
329	  if (d >= silence.warning) return 'warning';
330	  return 'normal';
331	}
