const QUESTION_PATTERNS = [
  /\?/,                                    // 问号
  /(what|how|when|where|which|who|why|whom)/i,
  /(can you|could you|would you|will you|do you|is it|are you|is there)/i,
  /(please.*(send|give|tell|quote|share|confirm|advise|provide|let me know|explain|clarify))/i,
  /(i need|i want|i would like|i'm looking for|we need|we want|we are looking)/i,
  /[吗呢吧啊]/,                             // 中文提问
  /[？]/,                                   // 中文问号
  /(价格|报价|多少钱|什么价)/,
  /(样品|sample|打样)/i,
  /(MOQ|起订量|最小.*量)/i,
  /(交期|delivery.*time|lead.*time)/i,
];

function isCustomerQuestion(text) {
  if (!text || text.length < 3) return false;
  for (const p of QUESTION_PATTERNS) {
    if (p.test(text)) return true;
  }
  return false;
}

// ── 回复质量评估 ──
function assessResponseQuality(questionText, responseText, gapHours) {
  if (!responseText || responseText.trim().length === 0) return { quality: '未回复', score: 0 };

  const respLen = responseText.trim().length;
  const vaguePatterns = /^(ok|okay|yes|no|thanks|thank you|got it|noted|well|sure|好的|收到|嗯|哦|知道了)[\s,.]*$/i;

  // 模糊/敷衍回复
  if (vaguePatterns.test(responseText.trim()) || respLen < 15) {
    return { quality: '敷衍回复', score: 1 };
  }

  // 简短回复 (15-50字)
  if (respLen < 50) {
    return { quality: '简短回复', score: 2 };
  }

  // 检查是否直接回应了问题关键词
  const qWords = questionText.toLowerCase().replace(/[?？,.]/g, '').split(/\s+/).filter(w => w.length > 3);
  const rLower = responseText.toLowerCase();
  const matchedWords = qWords.filter(w => rLower.includes(w));
  const relevanceRatio = qWords.length > 0 ? matchedWords.length / qWords.length : 0;

  if (relevanceRatio >= 0.3 || respLen >= 100) {
    return { quality: '充分回复', score: 3 };
  }

  return { quality: '简短回复', score: 2 };
}

// ── 处理所有 P1+P2 候选 ──
const candidates = [...(s1.results[1]||[]), ...(s1.results[2]||[])];
console.log('Processing ' + candidates.length + ' P1+P2 candidates...\n');

const enhanced = [];

for (const c of candidates) {
  const cid = c.cid;
  const filename = cid ? cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : '';
  const filePath = path.join(chatDir, filename);

  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
  let hasPI = false, hasAddress = false, hasOrderSignal = false, hasPrice = false;
  let hasSample = false, hasFreight = false, hasMOQ = false, hasQuantity = false;
  let latestOurMsg = '', latestOurDate = '';
  let latestCustMsg = '', latestCustDate = '';
  let lastCustomerMsgDays = 9999;

  // 新增：提问/回复分析
  let lastCustQuestion = '';
  let lastCustQuestionDate = '';
  let ourResponseQuality = 'N/A';
  let responseGapDays = -1;
  let questionUnanswered = false;

  if (fs.existsSync(filePath)) {
    try {
      const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
      const msgs = data.messages || [];
      msgCount = msgs.length;

      // 第一遍：基础统计
      for (const m of msgs) {
        const msg = m.message || m;
        const uid = msg.sender && msg.sender.uid || '';
        const content = msg.content;
        const text = getText(content);
        const date = msg.createAt || '';

        if (isSys(content)) { sysMsgs++; continue; }

        if (uid === OUR_UID) {
          ourMsgs++;
          if (date > latestOurDate) { latestOurDate = date; latestOurMsg = text; }
        } else if (uid) {
          customerMsgs++;
          if (date > latestCustDate) { latestCustDate = date; latestCustMsg = text; }
          if (date) {
            const d = Math.floor((NOW - new Date(date).getTime()) / DAY);
            lastCustomerMsgDays = Math.min(lastCustomerMsgDays, d);
          }
        }

        const lc = text.toLowerCase();
        if (/pi|proforma\s*invoice|invoice\s*sent/.test(lc)) hasPI = true;
        if (/(付款|deposit|定金)/.test(text)) hasPI = true;
        if (/(tt\s|wire\s*transfer|bank\s*transfer)/.test(lc)) hasPI = true;
        if (/(address|地址|city|country|delivery\s*address|where.*ship|send.*to|destination)/.test(lc)) hasAddress = true;
        if (/(place.*order|make.*order|confirm.*order|下单|order.*confirmed|want.*to.*order|proceed.*order|ready.*order)/.test(lc)) hasOrderSignal = true;
        if (/(price|price|quotation|quote|报价|unit.*price|each.*cost)/.test(lc)) hasPrice = true;
        if (/(sample|样品)/.test(lc)) hasSample = true;
        if (/(freight|shipping|运费|物流|delivery|transport|courier|dhl|fedex)/.test(lc)) hasFreight = true;
        if (/(moq|minimum.*order|最低.*数量|500.*piece|最小.*订单)/.test(lc)) hasMOQ = true;
        if (/(quantity|数量|how.*many|pieces|pcs|units)/.test(lc)) hasQuantity = true;
      }

      // 第二遍：找最后一个客户提问 + 我们是否回复
      // 从最新到最旧扫描客户消息，找第一个提问
      const sortedMsgs = [...msgs]
        .filter(m => {
          const msg = m.message || m;
          return !isSys(msg.content);
        })
        .sort((a, b) => {
          const da = (a.message || a).createAt || 0;
          const db = (b.message || b).createAt || 0;
          return db - da; // 最新的在前
        });

      for (const m of sortedMsgs) {
        const msg = m.message || m;
        const uid = msg.sender && msg.sender.uid || '';
        const text = getText(msg.content);
        const date = msg.createAt || '';

        if (uid && uid !== OUR_UID && isCustomerQuestion(text)) {
          lastCustQuestion = text;
          lastCustQuestionDate = date;
          break;
        }
      }

      // 找到了客户提问 → 分析回复
      if (lastCustQuestion && lastCustQuestionDate) {
        // 找提问之后的第一条我方回复
        let ourFirstResponse = '';
        let ourFirstResponseDate = '';
        const qTs = new Date(lastCustQuestionDate).getTime();

        for (const m of sortedMsgs.reverse()) { // 按时间正序
          const msg = m.message || m;
          const uid = msg.sender && msg.sender.uid || '';
          const date = msg.createAt || '';
          const ts = date ? new Date(date).getTime() : 0;

          if (uid === OUR_UID && ts > qTs) {
            ourFirstResponse = getText(msg.content);
            ourFirstResponseDate = date;
            break;
          }
        }

        if (ourFirstResponse) {
          const gapMs = new Date(ourFirstResponseDate).getTime() - qTs;
          const gapHours = gapMs / 3600000;
          responseGapDays = Math.round(gapHours / 24 * 10) / 10;

          const assessment = assessResponseQuality(lastCustQuestion, ourFirstResponse, gapHours);
          ourResponseQuality = assessment.quality + ' (' + responseGapDays + 'd)';
          questionUnanswered = false;
        } else {
          ourResponseQuality = '未回复';
          const gapMs = NOW - qTs;
          responseGapDays = Math.round(gapMs / DAY * 10) / 10;
          questionUnanswered = true;
        }
      }
    } catch(e) {
      // skip corrupted files
    }
  }

  const realMsgs = customerMsgs + ourMsgs;
  const daysAgo = c.daysAgo;
  const country = c.country || '';
  const coreMarkets = ['SD','EG','CD','ZM','CI','SA','AE'];
  const isCore = coreMarkets.includes(country);
  const cRatio = realMsgs > 0 ? Math.round(customerMsgs / realMsgs * 100) : 0;

  let tier = c.priority;
  const tierReason = [];

  // ── P0 升级触发 ──
  if (hasPI && hasAddress && daysAgo < 14 && realMsgs > 5) { tier = 0; tierReason.push('PI+地址已确认'); }
  if (hasOrderSignal && daysAgo < 7 && realMsgs > 5) { tier = 0; tierReason.push('下单信号'); }
  if (customerMsgs >= 3 && lastCustomerMsgDays <= 1 && ourMsgs === 0) { tier = 0; tierReason.push('客户多条新消息未回'); }
  if (hasPrice && hasAddress && hasQuantity && daysAgo < 7) { tier = 0; tierReason.push('报价+地址+数量(近成交)'); }
  if (customerMsgs >= 100 && daysAgo < 3) { tier = 0; tierReason.push('大量客户消息近期活跃'); }
  if (realMsgs > 50 && daysAgo < 3 && customerMsgs > 20 && lastCustomerMsgDays <= 2) { tier = 0; tierReason.push('高频互动客户活跃'); }

  // ── 【新】提问未回复升级 ──
  if (questionUnanswered && responseGapDays > 0.5 && lastCustomerMsgDays <= 3) {
    tier = 0;
    tierReason.push('客户提问' + responseGapDays + '天未回复');
  }
  if (questionUnanswered && responseGapDays > 1 && lastCustomerMsgDays <= 7) {
    tier = Math.min(tier, 0);
    tierReason.push('提问超1天未回');
  }

  // ── P1 升级触发 ──
  if (hasPI && daysAgo < 14) { tier = Math.min(tier, 1); tierReason.push('PI相关'); }
  if (isCore && realMsgs > 10 && daysAgo < 5) { tier = Math.min(tier, 1); tierReason.push('核心市场活跃对话'); }
  if (realMsgs > 20 && daysAgo < 5 && customerMsgs > 5) { tier = Math.min(tier, 1); tierReason.push('近期深度对话'); }
  if (hasAddress && realMsgs > 5 && daysAgo < 7) { tier = Math.min(tier, 1); tierReason.push('地址已给'); }

  // ── 【新】回复质量信号 ──
  if (ourResponseQuality.startsWith('敷衍回复') && isCore && daysAgo < 3) {
    tier = Math.min(tier, 1);
    tierReason.push('核心市场敷衍回复需补救');
  }
  if (ourResponseQuality.startsWith('简短回复') && daysAgo < 2 && isCore) {
    tier = Math.min(tier, 1);
    tierReason.push('核心市场回复质量待提升');
  }
  if (responseGapDays > 3 && questionUnanswered && isCore) {
    tier = Math.min(tier, 1);
    tierReason.push('核心客户提问超3天未回');
  }

  // ── 降级 ──
  if (realMsgs <= 2 && daysAgo > 7) { tier = Math.max(tier, c.priority + 1); tierReason.push('几乎无有效对话'); }

  enhanced.push({
    name: c.name,
    country, isCore, daysAgo, tier,
    tierName: 'P' + tier,
    tierReason: tierReason.length > 0 ? tierReason.join(', ') : '元数据',
    msgCount, customerMsgs, ourMsgs, sysMsgs, realMsgs, cRatio,
    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? '-' : lastCustomerMsgDays,
    latestOurMsg: latestOurMsg.substring(0, 100),
    latestCustMsg: latestCustMsg.substring(0, 100),
    hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasFreight, hasMOQ, hasQuantity,
    // 新增字段
    lastCustQuestion: lastCustQuestion.substring(0, 200),
    ourResponseQuality,
    responseGapDays,
    questionUnanswered,
    cid: c.cid, filename,
  });
}

// ── 排序 ──
enhanced.sort((a, b) => a.tier - b.tier || a.daysAgo - b.daysAgo);

// ── 输出 ──
const tiers = { 0: [], 1: [], 2: [], 3: [], 4: [] };
for (const e of enhanced) tiers[e.tier].push(e);

for (let t = 0; t <= 4; t++) {
  const items = tiers[t];
  if (items.length === 0) continue;
  console.log('=== P' + t + ': ' + items.length + ' people ===');
  for (const e of items) {
    const core = e.isCore ? '*' : ' ';
    const sig = [];
    if (e.hasPI) sig.push('PI');
    if (e.hasAddress) sig.push('ADDR');
    if (e.hasOrderSignal) sig.push('ORDER');
    if (e.hasPrice) sig.push('PRICE');
    if (e.hasSample) sig.push('SAMPLE');
    if (e.hasQuantity) sig.push('QTY');
    if (e.questionUnanswered) sig.push('⚠未回复');
    const sigStr = sig.length > 0 ? ' [' + sig.join(',') + ']' : '';
    const info = [
      String(e.daysAgo).padStart(2) + 'd',
      (e.country || '??').padEnd(2),
      core,
      e.name.padEnd(30),
      't:' + String(e.msgCount).padStart(4),
      'c:' + String(e.customerMsgs).padStart(4) + '/' + String(e.cRatio).padStart(2) + '%',
      e.tierReason.substring(0, 40).padEnd(40),
    ];
    console.log('  ' + info.join(' | ') + sigStr);
    if (e.latestCustMsg) {
      console.log('    cust last: ' + String(e.lastCustomerMsgDays) + 'd ago > ' + e.latestCustMsg.substring(0, 80));
    }
    // 显示提问/回复信号
    if (e.lastCustQuestion) {
      console.log('    ❓ Q: ' + e.lastCustQuestion.substring(0, 80));
      console.log('    💬 回复质量: ' + e.ourResponseQuality + ' | 间隔: ' + e.responseGapDays + 'd');
    }
  }
  console.log('');
}

// ── 摘要 ──
const tc = { 0: 0, 1: 0, 2: 0, 3: 0, 4: 0 };
for (const e of enhanced) tc[e.tier]++;
console.log('=== SUMMARY ===');
console.log('P0:' + tc[0] + ' P1:' + tc[1] + ' P2:' + tc[2] + ' Total:' + enhanced.length);
console.log('(from ' + (s1.results[1] || []).length + ' P1 + ' + (s1.results[2] || []).length + ' P2 metadata)');

// 提问未回复统计
const unanswered = enhanced.filter(e => e.questionUnanswered);
const poorQuality = enhanced.filter(e => e.ourResponseQuality.startsWith('敷衍回复') || e.ourResponseQuality.startsWith('简短回复'));
console.log('提问未回复: ' + unanswered.length + '人 | 回复质量待提升: ' + poorQuality.length + '人');

fs.writeFileSync(
  path.join(__dirname, '..', 'data', 's1_enhanced.json'),
  JSON.stringify(enhanced, null, 2)
);
console.log('\nSaved to data/s1_enhanced.json');

// ── 生成行动信号弹窗 HTML ──
generateActionPopup(enhanced, unanswered, poorQuality);

