${dangerSignals.length > 0 ? `
<div class="section">
  <div class="section-title signal">🚨 行动信号 — 需立即处理 (${dangerSignals.length}人)</div>
  <div style="padding: 16px 20px;">
    ${dangerSignals.map(e => {
      let advice = '';
      let cls = 'action-item';
