        advice = '上次回复过于简短/敷衍，建议补充详细信息或发送产品目录补救。';
        cls += ' warn';
      } else if (e.responseGapDays > 3) {
        advice = '回复客户提问间隔超过3天，跟进时效差。需立即联系确认是否还有需求。';
