      }
      return '<div class="' + cls + '">'
        + '<div class="action-header">'
        + '<span>' + e.name + ' <small>(' + (e.country||'??') + ')</small></span>'
        + '<span>' + (e.tier === 0 ? '<span class="badge p0-badge">P0</span>' : '<span class="badge p1-badge">P1</span>') + '</span>'
        + '</div>'
        + '<div class="action-detail">📌 ' + advice + '</div>'
        + (e.lastCustQuestion ? '<div class="action-q">❓ 客户提问: ' + e.lastCustQuestion.substring(0, 100) + '</div>' : '')
        + '<div class="action-detail" style="margin-top:4px;">回复质量: ' + e.ourResponseQuality + ' | 静默: ' + (e.lastCustomerMsgDays === '-' ? 'N/A' : e.lastCustomerMsgDays + 'd') + '</div>'
        + '</div>';
    }).join('\n    ')}
  </div>
</div>
` : ''}

${tiers[0].length > 0 ? `
<div class="section">
