    <tr><th>客户</th><th>国家</th><th>静默</th><th>提问</th><th>回复质量</th><th>间隔</th><th>分类理由</th></tr>
    ${tiers[0].map(e => `
    <tr>
      <td><b>${e.name}</b></td>
      <td>${e.country||'??'}${e.isCore ? ' ★' : ''}</td>
