      <td>${e.ourResponseQuality === 'N/A' ? '<span class="badge info">N/A</span>'
        : e.questionUnanswered ? '<span class="badge danger">未回复</span>'
        : e.ourResponseQuality.startsWith('敷衍') ? '<span class="badge warn">' + e.ourResponseQuality + '</span>'
        : e.ourResponseQuality.startsWith('简短') ? '<span class="badge warn">' + e.ourResponseQuality + '</span>'
        : '<span class="badge ok">' + e.ourResponseQuality + '</span>'
      }</td>
      <td>${e.responseGapDays >= 0 ? '<span class="' + (e.responseGapDays > 3 ? 'gap-highlight' : '') + '">' + e.responseGapDays + 'd</span>' : '-'}</td>
