        } else if (e.responseGapDays > 3) {
          advice = '回复间隔超过3天，跟进时效差，需立即联系确认';
        }
        return '<div class="' + (e.questionUnanswered ? 'action-item' : 'action-item warn') + '">'
          + '<div class="action-header">'
          + '<span>' + (i + 1) + '. ' + e.name + ' <small>(' + (e.country||'??') + ')</small> | ' + e.tierName + '</span>'
          + '<span style="font-size:12px;color:#888;">静默' + (e.lastCustomerMsgDays === '-' ? 'N/A' : e.lastCustomerMsgDays + 'd') + '</span>'
          + '</div>'
          + '<div class="action-detail">📌 ' + advice + '</div>'
          + (e.lastCustQuestion ? '<div class="action-q">❓ 客户提问: ' + e.lastCustQuestion.substring(0, 120) + '</div>' : '')
          + '<div class="action-detail" style="margin-top:4px;">💬 回复质量: ' + e.ourResponseQuality + '</div>'
          + '</div>';
      }).join('\n      ')}
      <div class="tip" style="margin-top:16px;">
