          {"field": "realMsgs", "op": "gte", "value": 5},
          {"field": "daysAgo", "op": "gt", "value": 7},
          {"field": "daysAgo", "op": "lte", "value": 30}
        ]
      },
      {
        "name": "有PI但超过7天未推进",
        "all": [
          {"field": "hasPI", "op": "eq", "value": true},
          {"field": "daysAgo", "op": "gt", "value": 7},
          {"field": "daysAgo", "op": "lte", "value": 30}
        ]
      },
      {
        "name": "少量互动+高客户消息占比(有潜力)",
        "all": [
          {"field": "realMsgs", "op": "gte", "value": 4},
          {"field": "realMsgs", "op": "lte", "value": 10},
          {"field": "cRatio", "op": "gte", "value": 30},
          {"field": "daysAgo", "op": "lte", "value": 14}
