  },

  "p3": {
    "label": "低优先级",
    "description": "有少量互动但近期沉默/超过30天未联系",
    "rules": [
      {
        "name": "1-3条消息但超过30天未联系",
        "all": [
          {"field": "realMsgs", "op": "gte", "value": 1},
          {"field": "realMsgs", "op": "lte", "value": 3},
          {"field": "daysAgo", "op": "gte", "value": 30}
        ]
      },
      {
        "name": "30-60天未联系但曾有互动",
        "all": [
          {"field": "daysAgo", "op": "gte", "value": 30},
          {"field": "daysAgo", "op": "lt", "value": 60},
          {"field": "realMsgs", "op": "gte", "value": 4},
          {"field": "realMsgs", "op": "lt", "value": 10}
        ]
      }
    ]
  },

  "p4": {
    "label": "沉默/沉睡",
    "description": "超过60天未联系或几乎无对话",
    "default": true
  },

  "silence_warnings": {
    "_说明": "沉默风险阈值(天数)，超过warning标黄，超过danger标红",
    "p0": {"warning": 2, "danger": 5},
    "p1": {"warning": 3, "danger": 7},
    "p2": {"warning": 7, "danger": 14},
    "p3": {"warning": 30, "danger": 60},
    "p4": {"warning": 60, "danger": 90}
  },

  "core_markets": ["SD", "EG", "CD", "ZM", "CI", "SA", "AE"],

  "system_msg_patterns": [
    "自动接待将不再触发",
    "Marco大模型翻译",
    "阿里国际Marco大模型翻译",
    "Since you have read the conversation",
    "买家有流失风险",
    "Buyer has churn risk",
    "一旦离开平台发生纠纷或欺诈",
    "由于您介入该会话",
    "Due to your intervention in this session",
