1	const fs = require('fs');
2	const path = require('path');
3	
4	const s1 = JSON.parse(fs.readFileSync(path.join(__dirname, '..', 'data', 's1_classification.json'), 'utf8'));
5	const chatDir = path.join(__dirname, '..', 'data', 'chat_history');
6	const NOW = Date.now();
7	const DAY = 86400000;
8	const OUR_UID = '2500000853693@icbu';
9	
10	const SYS_PATTERNS = [
11	  '自动接待将不再触发', 'Since you have read the conversation',
12	  'Marco大模型翻译', '阿里国际Marco大模型翻译',
13	  '买家有流失风险', 'Buyer has churn risk',
14	  '一旦离开平台发生纠纷或欺诈', '由于您介入该会话', 'Due to your intervention',
15	  '反馈', 'AI给您生成了一条回复建议',
16	  'You have a visitor', 'This buyer has been pre-screened',
17	  '当前买家首次给您发消息',
18	];
19	
20	function isSys(content) {
21	  const text = content && content.text && content.text.content || '';
22	  if (!text.trim()) return true;
23	  for (const p of SYS_PATTERNS) if (text.includes(p)) return true;
24	  return false;
25	}
26	
27	function getText(content) {
28	  return content && content.text && content.text.content || '';
29	}
30	
31	// ── 客户提问检测 ──
32	const QUESTION_PATTERNS = [
33	  /\?/,                                    // 问号
34	  /(what|how|when|where|which|who|why|whom)/i,
35	  /(can you|could you|would you|will you|do you|is it|are you|is there)/i,
36	  /(please.*(send|give|tell|quote|share|confirm|advise|provide|let me know|explain|clarify))/i,
37	  /(i need|i want|i would like|i'm looking for|we need|we want|we are looking)/i,
38	  /[吗呢吧啊]/,                             // 中文提问
39	  /[？]/,                                   // 中文问号
40	  /(价格|报价|多少钱|什么价)/,
41	  /(样品|sample|打样)/i,
42	  /(MOQ|起订量|最小.*量)/i,
43	  /(交期|delivery.*time|lead.*time)/i,
44	];
45	
46	function isCustomerQuestion(text) {
47	  if (!text || text.length < 3) return false;
48	  for (const p of QUESTION_PATTERNS) {
49	    if (p.test(text)) return true;
50	  }
51	  return false;
52	}
53	
54	// ── 回复质量评估 ──
55	function assessResponseQuality(questionText, responseText, gapHours) {
56	  if (!responseText || responseText.trim().length === 0) return { quality: '未回复', score: 0 };
57	
58	  const respLen = responseText.trim().length;
59	  const vaguePatterns = /^(ok|okay|yes|no|thanks|thank you|got it|noted|well|sure|好的|收到|嗯|哦|知道了)[\s,.]*$/i;
60	
61	  // 模糊/敷衍回复
62	  if (vaguePatterns.test(responseText.trim()) || respLen < 15) {
63	    return { quality: '敷衍回复', score: 1 };
64	  }
65	
66	  // 简短回复 (15-50字)
67	  if (respLen < 50) {
68	    return { quality: '简短回复', score: 2 };
69	  }
70	
71	  // 检查是否直接回应了问题关键词
72	  const qWords = questionText.toLowerCase().replace(/[?？,.]/g, '').split(/\s+/).filter(w => w.length > 3);
73	  const rLower = responseText.toLowerCase();
74	  const matchedWords = qWords.filter(w => rLower.includes(w));
75	  const relevanceRatio = qWords.length > 0 ? matchedWords.length / qWords.length : 0;
76	
77	  if (relevanceRatio >= 0.3 || respLen >= 100) {
78	    return { quality: '充分回复', score: 3 };
79	  }
80	
81	  return { quality: '简短回复', score: 2 };
82	}
83	
84	// ── 处理所有 P1+P2 候选 ──
85	const candidates = [...(s1.results[1]||[]), ...(s1.results[2]||[])];
86	console.log('Processing ' + candidates.length + ' P1+P2 candidates...\n');
87	
88	const enhanced = [];
89	
90	for (const c of candidates) {
91	  const cid = c.cid;
92	  const filename = cid ? cid.replace(/#/g, '_').replace(/@/g, '_') + '.json' : '';
93	  const filePath = path.join(chatDir, filename);
94	
95	  let msgCount = 0, customerMsgs = 0, ourMsgs = 0, sysMsgs = 0;
96	  let hasPI = false, hasAddress = false, hasOrderSignal = false, hasPrice = false;
97	  let hasSample = false, hasFreight = false, hasMOQ = false, hasQuantity = false;
98	  let latestOurMsg = '', latestOurDate = '';
99	  let latestCustMsg = '', latestCustDate = '';
100	  let lastCustomerMsgDays = 9999;
101	
102	  // 新增：提问/回复分析
103	  let lastCustQuestion = '';
104	  let lastCustQuestionDate = '';
105	  let ourResponseQuality = 'N/A';
106	  let responseGapDays = -1;
107	  let questionUnanswered = false;
108	
109	  if (fs.existsSync(filePath)) {
110	    try {
111	      const data = JSON.parse(fs.readFileSync(filePath, 'utf8'));
112	      const msgs = data.messages || [];
113	      msgCount = msgs.length;
114	
115	      // 第一遍：基础统计
116	      for (const m of msgs) {
117	        const msg = m.message || m;
118	        const uid = msg.sender && msg.sender.uid || '';
119	        const content = msg.content;
120	        const text = getText(content);
121	        const date = msg.createAt || '';
122	
123	        if (isSys(content)) { sysMsgs++; continue; }
124	
125	        if (uid === OUR_UID) {
126	          ourMsgs++;
127	          if (date > latestOurDate) { latestOurDate = date; latestOurMsg = text; }
128	        } else if (uid) {
129	          customerMsgs++;
130	          if (date > latestCustDate) { latestCustDate = date; latestCustMsg = text; }
131	          if (date) {
132	            const d = Math.floor((NOW - new Date(date).getTime()) / DAY);
133	            lastCustomerMsgDays = Math.min(lastCustomerMsgDays, d);
134	          }
135	        }
136	
137	        const lc = text.toLowerCase();
138	        if (/pi|proforma\s*invoice|invoice\s*sent/.test(lc)) hasPI = true;
139	        if (/(付款|deposit|定金)/.test(text)) hasPI = true;
140	        if (/(tt\s|wire\s*transfer|bank\s*transfer)/.test(lc)) hasPI = true;
141	        if (/(address|地址|city|country|delivery\s*address|where.*ship|send.*to|destination)/.test(lc)) hasAddress = true;
142	        if (/(place.*order|make.*order|confirm.*order|下单|order.*confirmed|want.*to.*order|proceed.*order|ready.*order)/.test(lc)) hasOrderSignal = true;
143	        if (/(price|price|quotation|quote|报价|unit.*price|each.*cost)/.test(lc)) hasPrice = true;
144	        if (/(sample|样品)/.test(lc)) hasSample = true;
145	        if (/(freight|shipping|运费|物流|delivery|transport|courier|dhl|fedex)/.test(lc)) hasFreight = true;
146	        if (/(moq|minimum.*order|最低.*数量|500.*piece|最小.*订单)/.test(lc)) hasMOQ = true;
147	        if (/(quantity|数量|how.*many|pieces|pcs|units)/.test(lc)) hasQuantity = true;
148	      }
149	
150	      // 第二遍：找最后一个客户提问 + 我们是否回复
151	      // 从最新到最旧扫描客户消息，找第一个提问
152	      const sortedMsgs = [...msgs]
153	        .filter(m => {
154	          const msg = m.message || m;
155	          return !isSys(msg.content);
156	        })
157	        .sort((a, b) => {
158	          const da = (a.message || a).createAt || 0;
159	          const db = (b.message || b).createAt || 0;
160	          return db - da; // 最新的在前
161	        });
162	
163	      for (const m of sortedMsgs) {
164	        const msg = m.message || m;
165	        const uid = msg.sender && msg.sender.uid || '';
166	        const text = getText(msg.content);
167	        const date = msg.createAt || '';
168	
169	        if (uid && uid !== OUR_UID && isCustomerQuestion(text)) {
170	          lastCustQuestion = text;
171	          lastCustQuestionDate = date;
172	          break;
173	        }
174	      }
175	
176	      // 找到了客户提问 → 分析回复
177	      if (lastCustQuestion && lastCustQuestionDate) {
178	        // 找提问之后的第一条我方回复
179	        let ourFirstResponse = '';
180	        let ourFirstResponseDate = '';
181	        const qTs = new Date(lastCustQuestionDate).getTime();
182	
183	        for (const m of sortedMsgs.reverse()) { // 按时间正序
184	          const msg = m.message || m;
185	          const uid = msg.sender && msg.sender.uid || '';
186	          const date = msg.createAt || '';
187	          const ts = date ? new Date(date).getTime() : 0;
188	
189	          if (uid === OUR_UID && ts > qTs) {
190	            ourFirstResponse = getText(msg.content);
191	            ourFirstResponseDate = date;
192	            break;
193	          }
194	        }
195	
196	        if (ourFirstResponse) {
197	          const gapMs = new Date(ourFirstResponseDate).getTime() - qTs;
198	          const gapHours = gapMs / 3600000;
199	          responseGapDays = Math.round(gapHours / 24 * 10) / 10;
200	
201	          const assessment = assessResponseQuality(lastCustQuestion, ourFirstResponse, gapHours);
202	          ourResponseQuality = assessment.quality + ' (' + responseGapDays + 'd)';
203	          questionUnanswered = false;
204	        } else {
205	          ourResponseQuality = '未回复';
206	          const gapMs = NOW - qTs;
207	          responseGapDays = Math.round(gapMs / DAY * 10) / 10;
208	          questionUnanswered = true;
209	        }
210	      }
211	    } catch(e) {
212	      // skip corrupted files
213	    }
214	  }
215	
216	  const realMsgs = customerMsgs + ourMsgs;
217	  const daysAgo = c.daysAgo;
218	  const country = c.country || '';
219	  const coreMarkets = ['SD','EG','CD','ZM','CI','SA','AE'];
220	  const isCore = coreMarkets.includes(country);
221	  const cRatio = realMsgs > 0 ? Math.round(customerMsgs / realMsgs * 100) : 0;
222	
223	  let tier = c.priority;
224	  const tierReason = [];
225	
226	  // ── P0 升级触发 ──
227	  if (hasPI && hasAddress && daysAgo < 14 && realMsgs > 5) { tier = 0; tierReason.push('PI+地址已确认'); }
228	  if (hasOrderSignal && daysAgo < 7 && realMsgs > 5) { tier = 0; tierReason.push('下单信号'); }
229	  if (customerMsgs >= 3 && lastCustomerMsgDays <= 1 && ourMsgs === 0) { tier = 0; tierReason.push('客户多条新消息未回'); }
230	  if (hasPrice && hasAddress && hasQuantity && daysAgo < 7) { tier = 0; tierReason.push('报价+地址+数量(近成交)'); }
231	  if (customerMsgs >= 100 && daysAgo < 3) { tier = 0; tierReason.push('大量客户消息近期活跃'); }
232	  if (realMsgs > 50 && daysAgo < 3 && customerMsgs > 20 && lastCustomerMsgDays <= 2) { tier = 0; tierReason.push('高频互动客户活跃'); }
233	
234	  // ── 【新】提问未回复升级 ──
235	  if (questionUnanswered && responseGapDays > 0.5 && lastCustomerMsgDays <= 3) {
236	    tier = 0;
237	    tierReason.push('客户提问' + responseGapDays + '天未回复');
238	  }
239	  if (questionUnanswered && responseGapDays > 1 && lastCustomerMsgDays <= 7) {
240	    tier = Math.min(tier, 0);
241	    tierReason.push('提问超1天未回');
242	  }
243	
244	  // ── P1 升级触发 ──
245	  if (hasPI && daysAgo < 14) { tier = Math.min(tier, 1); tierReason.push('PI相关'); }
246	  if (isCore && realMsgs > 10 && daysAgo < 5) { tier = Math.min(tier, 1); tierReason.push('核心市场活跃对话'); }
247	  if (realMsgs > 20 && daysAgo < 5 && customerMsgs > 5) { tier = Math.min(tier, 1); tierReason.push('近期深度对话'); }
248	  if (hasAddress && realMsgs > 5 && daysAgo < 7) { tier = Math.min(tier, 1); tierReason.push('地址已给'); }
249	
250	  // ── 【新】回复质量信号 ──
251	  if (ourResponseQuality.startsWith('敷衍回复') && isCore && daysAgo < 3) {
252	    tier = Math.min(tier, 1);
253	    tierReason.push('核心市场敷衍回复需补救');
254	  }
255	  if (ourResponseQuality.startsWith('简短回复') && daysAgo < 2 && isCore) {
256	    tier = Math.min(tier, 1);
257	    tierReason.push('核心市场回复质量待提升');
258	  }
259	  if (responseGapDays > 3 && questionUnanswered && isCore) {
260	    tier = Math.min(tier, 1);
261	    tierReason.push('核心客户提问超3天未回');
262	  }
263	
264	  // ── 降级 ──
265	  if (realMsgs <= 2 && daysAgo > 7) { tier = Math.max(tier, c.priority + 1); tierReason.push('几乎无有效对话'); }
266	
267	  enhanced.push({
268	    name: c.name,
269	    country, isCore, daysAgo, tier,
270	    tierName: 'P' + tier,
271	    tierReason: tierReason.length > 0 ? tierReason.join(', ') : '元数据',
272	    msgCount, customerMsgs, ourMsgs, sysMsgs, realMsgs, cRatio,
273	    lastCustomerMsgDays: lastCustomerMsgDays === 9999 ? '-' : lastCustomerMsgDays,
274	    latestOurMsg: latestOurMsg.substring(0, 100),
275	    latestCustMsg: latestCustMsg.substring(0, 100),
276	    hasPI, hasAddress, hasOrderSignal, hasPrice, hasSample, hasFreight, hasMOQ, hasQuantity,
277	    // 新增字段
278	    lastCustQuestion: lastCustQuestion.substring(0, 200),
279	    ourResponseQuality,
280	    responseGapDays,
281	    questionUnanswered,
282	    cid: c.cid, filename,
283	  });
284	}
285	
286	// ── 排序 ──
287	enhanced.sort((a, b) => a.tier - b.tier || a.daysAgo - b.daysAgo);
288	
289	// ── 输出 ──
290	const tiers = { 0: [], 1: [], 2: [], 3: [], 4: [] };
291	for (const e of enhanced) tiers[e.tier].push(e);
292	
293	for (let t = 0; t <= 4; t++) {
294	  const items = tiers[t];
295	  if (items.length === 0) continue;
296	  console.log('=== P' + t + ': ' + items.length + ' people ===');
297	  for (const e of items) {
298	    const core = e.isCore ? '*' : ' ';
299	    const sig = [];
300	    if (e.hasPI) sig.push('PI');
301	    if (e.hasAddress) sig.push('ADDR');
302	    if (e.hasOrderSignal) sig.push('ORDER');
303	    if (e.hasPrice) sig.push('PRICE');
304	    if (e.hasSample) sig.push('SAMPLE');
305	    if (e.hasQuantity) sig.push('QTY');
306	    if (e.questionUnanswered) sig.push('⚠未回复');
307	    const sigStr = sig.length > 0 ? ' [' + sig.join(',') + ']' : '';
308	    const info = [
309	      String(e.daysAgo).padStart(2) + 'd',
310	      (e.country || '??').padEnd(2),
311	      core,
312	      e.name.padEnd(30),
313	      't:' + String(e.msgCount).padStart(4),
314	      'c:' + String(e.customerMsgs).padStart(4) + '/' + String(e.cRatio).padStart(2) + '%',
315	      e.tierReason.substring(0, 40).padEnd(40),
316	    ];
317	    console.log('  ' + info.join(' | ') + sigStr);
318	    if (e.latestCustMsg) {
319	      console.log('    cust last: ' + String(e.lastCustomerMsgDays) + 'd ago > ' + e.latestCustMsg.substring(0, 80));
320	    }
321	    // 显示提问/回复信号
322	    if (e.lastCustQuestion) {
323	      console.log('    ❓ Q: ' + e.lastCustQuestion.substring(0, 80));
324	      console.log('    💬 回复质量: ' + e.ourResponseQuality + ' | 间隔: ' + e.responseGapDays + 'd');
325	    }
326	  }
327	  console.log('');
328	}
329	
330	// ── 摘要 ──
331	const tc = { 0: 0, 1: 0, 2: 0, 3: 0, 4: 0 };
332	for (const e of enhanced) tc[e.tier]++;
333	console.log('=== SUMMARY ===');
334	console.log('P0:' + tc[0] + ' P1:' + tc[1] + ' P2:' + tc[2] + ' Total:' + enhanced.length);
335	console.log('(from ' + (s1.results[1] || []).length + ' P1 + ' + (s1.results[2] || []).length + ' P2 metadata)');
336	
337	// 提问未回复统计
338	const unanswered = enhanced.filter(e => e.questionUnanswered);
339	const poorQuality = enhanced.filter(e => e.ourResponseQuality.startsWith('敷衍回复') || e.ourResponseQuality.startsWith('简短回复'));
340	console.log('提问未回复: ' + unanswered.length + '人 | 回复质量待提升: ' + poorQuality.length + '人');
341	
342	fs.writeFileSync(
343	  path.join(__dirname, '..', 'data', 's1_enhanced.json'),
344	  JSON.stringify(enhanced, null, 2)
345	);
346	console.log('\nSaved to data/s1_enhanced.json');
347	
348	// ── 生成行动信号弹窗 HTML ──
349	generateActionPopup(enhanced, unanswered, poorQuality);
350	
351	function generateActionPopup(enhanced, unanswered, poorQuality) {
352	  const now = new Date();
353	  const todayStr = now.toISOString().slice(0, 10);
354	  const nowStr = now.toLocaleString('zh-CN');
355	
356	  const tiers = { 0: [], 1: [], 2: [], 3: [], 4: [] };
357	  for (const e of enhanced) tiers[e.tier].push(e);
358	
359	  const dangerSignals = enhanced.filter(e =>
360	    e.questionUnanswered ||
361	    (e.ourResponseQuality.startsWith('敷衍回复') && e.daysAgo < 3) ||
362	    e.responseGapDays > 3
363	  );
364	
365	  const html = `<!DOCTYPE html>
366	<html lang="zh">
